#include <stdio.h>
#include <stdint.h>

/*
 * ALU Operations Implementation in C
 * Demonstrates arithmetic, logical, and shift operations
 * with status flag handling (like real hardware)
 */

#define BIT_SIZE 8
#define MAX_VALUE ((1 << BIT_SIZE) - 1)

// Status flags structure (like CPU flag register)
typedef struct {
 uint8_t zero : 1; // Z: Result is zero
 uint8_t carry : 1; // C: Carry out or borrow
 uint8_t overflow : 1; // V: Signed overflow
 uint8_t sign : 1; // S: Negative result
 uint8_t unused : 4;
} StatusFlags;

// ALU structure
typedef struct {
 uint8_t operand1;
 uint8_t operand2;
 uint8_t result;
 StatusFlags flags;
} ALU;

// Initialize ALU
void alu_init(ALU *alu) {
 alu->operand1 = 0;
 alu->operand2 = 0;
 alu->result = 0;
 alu->flags.zero = 0;
 alu->flags.carry = 0;
 alu->flags.overflow = 0;
 alu->flags.sign = 0;
}

// Set flags based on result
void alu_set_flags(ALU *alu, uint8_t result) {
 alu->result = result & MAX_VALUE; // Truncate to bit size

 // Zero flag
 alu->flags.zero = (alu->result == 0) ? 1 : 0;

 // Sign flag (MSB)
 alu->flags.sign = (alu->result >> (BIT_SIZE - 1)) & 1;
}

// ADD operation
uint8_t alu_add(ALU *alu, uint8_t a, uint8_t b) {
 alu->operand1 = a;
 alu->operand2 = b;

 uint16_t raw_result = (uint16_t)a + (uint16_t)b;

 // Carry flag (unsigned overflow)
 alu->flags.carry = (raw_result > MAX_VALUE) ? 1 : 0;

 // Overflow flag (signed overflow)
 int8_t a_signed = (int8_t)a;
 int8_t b_signed = (int8_t)b;
 int8_t r_signed = (int8_t)(raw_result & MAX_VALUE);
 alu->flags.overflow = ((a_signed > 0 && b_signed > 0 && r_signed < 0) ||
 (a_signed < 0 && b_signed < 0 && r_signed > 0)) ? 1 : 0;

 alu_set_flags(alu, (uint8_t)raw_result);
 return alu->result;
}

// SUBTRACT operation
uint8_t alu_sub(ALU *alu, uint8_t a, uint8_t b) {
 alu->operand1 = a;
 alu->operand2 = b;

 int16_t raw_result = (int16_t)a - (int16_t)b;

 // Borrow/Carry flag
 alu->flags.carry = (a < b) ? 1 : 0;

 // Overflow flag
 int8_t a_signed = (int8_t)a;
 int8_t b_signed = (int8_t)b;
 int8_t r_signed = (int8_t)(raw_result & MAX_VALUE);
 alu->flags.overflow = ((a_signed > 0 && b_signed < 0 && r_signed < 0) ||
 (a_signed < 0 && b_signed > 0 && r_signed > 0)) ? 1 : 0;

 alu_set_flags(alu, (uint8_t)(raw_result & MAX_VALUE));
 return alu->result;
}

// AND operation
uint8_t alu_and(ALU *alu, uint8_t a, uint8_t b) {
 alu->operand1 = a;
 alu->operand2 = b;
 alu->flags.carry = 0;
 alu->flags.overflow = 0;
 alu_set_flags(alu, a & b);
 return alu->result;
}

// OR operation
uint8_t alu_or(ALU *alu, uint8_t a, uint8_t b) {
 alu->operand1 = a;
 alu->operand2 = b;
 alu->flags.carry = 0;
 alu->flags.overflow = 0;
 alu_set_flags(alu, a | b);
 return alu->result;
}

// XOR operation
uint8_t alu_xor(ALU *alu, uint8_t a, uint8_t b) {
 alu->operand1 = a;
 alu->operand2 = b;
 alu->flags.carry = 0;
 alu->flags.overflow = 0;
 alu_set_flags(alu, a ^ b);
 return alu->result;
}

// NOT operation (unary)
uint8_t alu_not(ALU *alu, uint8_t a) {
 alu->operand1 = a;
 alu->flags.carry = 0;
 alu->flags.overflow = 0;
 alu_set_flags(alu, (~a) & MAX_VALUE);
 return alu->result;
}

// Logical Shift Left
uint8_t alu_shl(ALU *alu, uint8_t a) {
 alu->operand1 = a;
 uint8_t result = (a << 1) & MAX_VALUE;
 // Carry = bit shifted out
 alu->flags.carry = (a >> (BIT_SIZE - 1)) & 1;
 alu->flags.overflow = 0;
 alu_set_flags(alu, result);
 return alu->result;
}

// Logical Shift Right
uint8_t alu_shr(ALU *alu, uint8_t a) {
 alu->operand1 = a;
 uint8_t result = a >> 1;
 // Carry = bit shifted out
 alu->flags.carry = a & 1;
 alu->flags.overflow = 0;
 alu_set_flags(alu, result);
 return alu->result;
}

// Compare operation (sets flags only)
void alu_compare(ALU *alu, uint8_t a, uint8_t b) {
 alu->operand1 = a;
 alu->operand2 = b;

 int16_t diff = (int16_t)a - (int16_t)b;
 uint8_t result = diff & MAX_VALUE;

 alu->flags.zero = (result == 0) ? 1 : 0;
 alu->flags.carry = (a < b) ? 1 : 0;

 int8_t a_signed = (int8_t)a;
 int8_t b_signed = (int8_t)b;
 int8_t r_signed = (int8_t)result;
 alu->flags.overflow = ((a_signed > 0 && b_signed < 0 && r_signed < 0) ||
 (a_signed < 0 && b_signed > 0 && r_signed > 0)) ? 1 : 0;
 alu->flags.sign = (r_signed < 0) ? 1 : 0;

 alu->result = result;
}

// Print flags
void print_flags(ALU *alu) {
 printf("Flags: Z=%d C=%d V=%d S=%d", 
 alu->flags.zero, 
 alu->flags.carry, 
 alu->flags.overflow, 
 alu->flags.sign);
}

// Main - Demonstration
int main() {
 ALU alu;
 alu_init(&alu);

 printf("===========================================\n");
 printf(" ALU OPERATIONS - C IMPLEMENTATION\n");
 printf(" (8-bit operations with flags)\n");
 printf("===========================================\n\n");

 // Test ADD
 printf("ADD: 200 + 100\n");
 alu_add(&alu, 200, 100);
 printf(" Result: %d (0x%02X) ", alu.result, alu.result);
 print_flags(&alu);
 printf("\n\n");

 // Test SUB
 printf("SUB: 50 - 30\n");
 alu_sub(&alu, 50, 30);
 printf(" Result: %d (0x%02X) ", alu.result, alu.result);
 print_flags(&alu);
 printf("\n\n");

 // Test AND
 printf("AND: 0xF0 & 0x0F\n");
 alu_and(&alu, 0xF0, 0x0F);
 printf(" Result: %d (0x%02X) ", alu.result, alu.result);
 print_flags(&alu);
 printf("\n\n");

 // Test OR
 printf("OR: 0xF0 | 0x0F\n");
 alu_or(&alu, 0xF0, 0x0F);
 printf(" Result: %d (0x%02X) ", alu.result, alu.result);
 print_flags(&alu);
 printf("\n\n");

 // Test XOR
 printf("XOR: 0xFF ^ 0xFF\n");
 alu_xor(&alu, 0xFF, 0xFF);
 printf(" Result: %d (0x%02X) ", alu.result, alu.result);
 print_flags(&alu);
 printf("\n\n");

 // Test NOT
 printf("NOT: ~0x00\n");
 alu_not(&alu, 0x00);
 printf(" Result: %d (0x%02X) ", alu.result, alu.result);
 print_flags(&alu);
 printf("\n\n");

 // Test Shift Left
 printf("SHL: 0x40 << 1\n");
 alu_shl(&alu, 0x40);
 printf(" Result: %d (0x%02X) ", alu.result, alu.result);
 print_flags(&alu);
 printf("\n\n");

 // Test Compare
 printf("CMP: 50 vs 50 (equal)\n");
 alu_compare(&alu, 50, 50);
 print_flags(&alu);
 printf("\n\n");

 printf("CMP: 30 vs 50 (less than)\n");
 alu_compare(&alu, 30, 50);
 print_flags(&alu);
 printf("\n");

 return 0;
}
